import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read a full line of input

        // Limiting the size of the name to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Name is too long. Please enter a name with 10 characters or less.");
            return;
        }

        System.out.println("Hello, " + name);
    }
}

